previewCss:
.darma-loader-uiverse-aqua-ripple-tiles {
  --cell-size: 52px;
  --cell-spacing: 1px;
  --cells: 3;
  --total-size: calc(var(--cells) * (var(--cell-size) + 2 * var(--cell-spacing)));
  display: flex;
  flex-wrap: wrap;
  width: var(--total-size);
  height: var(--total-size);
}

.darma-loader-uiverse-aqua-ripple-tiles__cell {
flex: 0 0 var(--cell-size);
margin: var(--cell-spacing);
background-color: transparent;
box-sizing: border-box;
border-radius: 4px;
animation: 1.5s darma-loader-uiverse-aqua-ripple-tiles-ripple ease infinite;
}

.darma-loader-uiverse-aqua-ripple-tiles__cell.darma-loader-uiverse-aqua-ripple-tiles__d-1 {
animation-delay: 100ms;
}

.darma-loader-uiverse-aqua-ripple-tiles__cell.darma-loader-uiverse-aqua-ripple-tiles__d-2 {
animation-delay: 200ms;
}

.darma-loader-uiverse-aqua-ripple-tiles__cell.darma-loader-uiverse-aqua-ripple-tiles__d-3 {
animation-delay: 300ms;
}

.darma-loader-uiverse-aqua-ripple-tiles__cell.darma-loader-uiverse-aqua-ripple-tiles__d-4 {
animation-delay: 400ms;
}

.darma-loader-uiverse-aqua-ripple-tiles__cell:nth-child(1) {
--cell-color: #00FF87;
}

.darma-loader-uiverse-aqua-ripple-tiles__cell:nth-child(2) {
--cell-color: #0CFD95;
}

.darma-loader-uiverse-aqua-ripple-tiles__cell:nth-child(3) {
--cell-color: #17FBA2;
}

.darma-loader-uiverse-aqua-ripple-tiles__cell:nth-child(4) {
--cell-color: #23F9B2;
}

.darma-loader-uiverse-aqua-ripple-tiles__cell:nth-child(5) {
--cell-color: #30F7C3;
}

.darma-loader-uiverse-aqua-ripple-tiles__cell:nth-child(6) {
--cell-color: #3DF5D4;
}

.darma-loader-uiverse-aqua-ripple-tiles__cell:nth-child(7) {
--cell-color: #45F4DE;
}

.darma-loader-uiverse-aqua-ripple-tiles__cell:nth-child(8) {
--cell-color: #53F1F0;
}

.darma-loader-uiverse-aqua-ripple-tiles__cell:nth-child(9) {
--cell-color: #60EFFF;
}

/*Animation*/
@keyframes darma-loader-uiverse-aqua-ripple-tiles-ripple {
0% {
background-color: transparent;
}

30% {
background-color: var(--cell-color);
}

60% {
background-color: transparent;
}

100% {
background-color: transparent;
}
}

